import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Button, Input, Alert } from '../components/ui';
import { Zap, User, Lock } from 'lucide-react';
import './AuthPages.css';

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ username: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handle = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const submit = async e => {
    e.preventDefault();
    if (!form.username || !form.password) return setError('Please fill all fields.');
    setLoading(true); setError('');
    try {
      await login(form.username, form.password);
      navigate('/dashboard');
    } catch (err) {
      const detail = err.response?.data?.detail;
      if (Array.isArray(detail)) {
        setError(detail.map(d => d.msg || JSON.stringify(d)).join(', '));
      } else {
        setError(typeof detail === 'string' ? detail : 'Invalid credentials.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-left">
        <div className="auth-brand">
          <div className="auth-brand-icon"><Zap size={22} /></div>
          <span>DB Assistant</span>
        </div>
        <div className="auth-headline">
          <h1>Query your databases<br />with plain English.</h1>
          <p>No SQL expertise needed. Powered by Google Gemini AI.</p>
        </div>
        <div className="auth-features">
          {['Natural language → SQL in seconds', 'PostgreSQL & MongoDB support', 'AI-powered EDA & charts', 'Secure encrypted connections'].map(f => (
            <div key={f} className="auth-feature"><span className="auth-feature-dot" />{f}</div>
          ))}
        </div>
      </div>

      <div className="auth-right">
        <div className="auth-card fade-in">
          <div className="auth-card-header">
            <h2>Welcome back</h2>
            <p>Sign in to your account</p>
          </div>

          {error && <Alert type="error" onClose={() => setError('')}>{error}</Alert>}

          <form onSubmit={submit} className="auth-form">
            <Input
              label="Username"
              name="username"
              value={form.username}
              onChange={handle}
              placeholder="Enter your username"
              icon={<User size={15} />}
              autoComplete="username"
              autoFocus
            />
            <Input
              label="Password"
              name="password"
              type="password"
              value={form.password}
              onChange={handle}
              placeholder="Enter your password"
              icon={<Lock size={15} />}
              autoComplete="current-password"
            />
            <Button type="submit" size="lg" loading={loading} style={{ width: '100%', marginTop: 4 }}>
              Sign in
            </Button>
          </form>

          <p className="auth-switch">
            Don't have an account? <Link to="/register">Create one →</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
